INSERT INTO `sys_help` VALUES (1, '功能及核心流程介绍', '<p style=\"font-size: 0px; line-height: 0; margin: 0px;\">&nbsp;</p><section style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px\"><h1 id=\"0\" style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 1em; border-bottom: 2px solid #0F4C81; margin: 2em auto 1em; color: #3f3f3f; font-weight: bold;margin-top: 0\" data-heading=\"true\">启航电商ERP系统2.0版</h1><blockquote style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; font-style: normal; padding: 1em; border-left: 4px solid #0F4C81; border-radius: 6px; color: rgba(0,0,0,0.5); background: #f7f7f7; margin-bottom: 1em\"><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 1em; display: block; letter-spacing: 0.1em; color: #3f3f3f\"><strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">欢迎来到我们的开源项目！创新、协作、高质量的代码。您的Star🌟，是我们前进的动力！ 💪✨🏆</strong></p></blockquote><blockquote style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; font-style: normal; padding: 1em; border-left: 4px solid #0F4C81; border-radius: 6px; color: rgba(0,0,0,0.5); background: #f7f7f7; margin-bottom: 1em\"><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 1em; display: block; letter-spacing: 0.1em; color: #3f3f3f\"><strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">项目持续更新中，还有很多不足，请多包含！如有任何疑问请提交issuse！谢谢！ 💪✨🏆</strong></p></blockquote><h2 id=\"1\" style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\" data-heading=\"true\">一、系统介绍</h2><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">启航电商ERP系统2.0版本是一个完整开箱即用的开源电商ERP系统，经历1.0版本的迭代优化和客户使用验证。开发者可以直接部署即可使用。</p><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">启航电商ERP系统是一个专注核心订单处理业务，主体功能包括：商品管理、店铺商品管理、订单库、店铺订单管理、发货管理（支持多供应商发货）、电子面单打印、售后管理、库存管理等。</p><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">与此同时该系统会陆续增加供外部调用的API，以便开发者满足自己的个性化业务需求。</p><p style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">启航电商ERP系统支持：淘宝天猫、拼多多、抖店、微信小店等平台，后续将继续对接其他电商平台。</p><figure style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; color: #3f3f3f\"><img alt=\"\" title=\"null\" src=\"docs/preview.png\" style=\"text-align: left; line-height: 1.75; font-family: -apple-system-font, BlinkMacSystemFont, &quot;Helvetica Neue&quot;, &quot;PingFang SC&quot;, &quot;Hiragino Sans GB&quot;, &quot;Microsoft YaHei UI&quot;, &quot;Microsoft YaHei&quot;, Arial, sans-serif; font-size: 14px; display: block; margin: 0.1em auto 0.5em; border-radius: 4px;\"><figcaption style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 0.8em; color: #888\"></figcaption></figure><h2 id=\"2\" style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\" data-heading=\"true\">二、系统特点</h2><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 1、启航电商ERP系统是一个专注核心业务处理并且又能快速方便扩展个性化需求的一个底座。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 2、启航电商ERP2.0版本是一个部署即可使用的开源电商ERP系统。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 3、该系统适合想自研电商系统的企业快速构建业务。<strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">系统并不适合小卖家，小卖家还是老老实实使用市面上流行的SAAS吧。</strong></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 4、使用启航电商ERP系统的前置条件是：<strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">自行申请各电商开放平台的AppKey</strong> <a style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; color: #576b95; text-decoration: none\" title=\"开放平台申请说明\" href=\"https://mp.weixin.qq.com/s/KqyNlIVl43dTWicaAeLR1g\">开放平台申请说明</a></li></ul><h2 id=\"3\" style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\" data-heading=\"true\">三、功能模块</h2><h4 id=\"4\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">1、商品管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品库管理：管理商品库商品，提供手动录入、API接收功能，可以设置自己发货还是供应商发货（影响到后台分单逻辑，即时生效）。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品库SKU明细：查看所有商品库SKU</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺商品管理：店铺商品管理，店铺商品API拉取、店铺商品API更新（进行店铺商品与商品库商品关联，根据SKU编码关联）。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品分类管理</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品品牌管理</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 供应商管理</li></ul><h4 id=\"5\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">2、订单管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单库：聚合订单查询、详情、管理。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单明细：聚合订单明细查询。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺订单管理：订单API拉取、订单API更新、订单手动推送等，支持淘宝天猫、京东、拼多多、抖店、微信视频号。</li></ul><h4 id=\"6\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">3、发货管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 待发货清单：（商品维度、订单维度），展示待分配发货的清单（系统会根据商品设置的自己发货还是供应商发货自动分配到发货订单库）</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 取号发货：电子面单取号发货</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单打印：电子面单打印，支持淘宝天猫、京东、拼多多、抖店、微信视频号。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 备货出库：电子面单取号之后会加入备货清单，提供给仓库备货查询。发货之后会从备货清单中移除。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 发货记录：发货记录，提供手动发货功能。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 物流跟踪：提供发货物流查询。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 快递快递管理：管理发货的快递公司（支持从平台拉取、支持线下渠道手动添加发货快递）。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 面单账户管理：管理店铺开通的电子面单账户</li></ul><h4 id=\"7\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">4、售后管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后中新：聚合售后查询、详情、管理。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺售后管理：售后API拉取、售后API更新、手动推送、售后操作（同意、备注）。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后处理记录：售后处理的记录查询，提供手动售后处理功能。</li></ul><h4 id=\"8\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">5、库存管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品库存管理：查询库存</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品入库管理：支持手动入库</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 商品出库管理：支持手动出库</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 仓库仓位设置</li></ul><h4 id=\"9\" style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\" data-heading=\"true\">6、店铺&amp;平台设置</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺管理</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 平台设置</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单更新日志：查询更新日志，主动排错。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后更新日志：查询更新日志，主动排错。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 定时任务配置</li></ul><h2 id=\"10\" style=\" text-align: center; line-height: 1.75; font-famil