t=\"24\" width=\"112\"><section xmlns=\"http://www.w3.org/1999/xhtml\" style=\"display: table-cell; white-space: nowrap; line-height: 1.5; max-width: 200px; text-align: center;\"><span class=\"nodeLabel\" style=\"fill: #333; color: #333;\">通知消费者拒收</span></section></foreignObject></g></g><g transform=\"translate(746, 35)\" id=\"flowchart-H-9\" class=\"node default\"><rect height=\"54\" width=\"140\" y=\"-27\" x=\"-70\" style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\" class=\"basic label-container\"></rect><g transform=\"translate(-40, -12)\" style=\"font-family: \'trebuchet ms\',verdana,arial,sans-serif; color: #333; text-align: center;\" class=\"label\"><rect style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\"></rect><foreignObject height=\"24\" width=\"80\"><section xmlns=\"http://www.w3.org/1999/xhtml\" style=\"display: table-cell; white-space: nowrap; line-height: 1.5; max-width: 200px; text-align: center;\"><span class=\"nodeLabel\" style=\"fill: #333; color: #333;\">消费者拒收</span></section></foreignObject></g></g><g transform=\"translate(928, 35)\" id=\"flowchart-C-11\" class=\"node default\"><rect height=\"54\" width=\"124\" y=\"-27\" x=\"-62\" style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\" class=\"basic label-container\"></rect><g transform=\"translate(-32, -12)\" style=\"font-family: \'trebuchet ms\',verdana,arial,sans-serif; color: #333; text-align: center;\" class=\"label\"><rect style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\"></rect><foreignObject height=\"24\" width=\"64\"><section xmlns=\"http://www.w3.org/1999/xhtml\" style=\"display: table-cell; white-space: nowrap; line-height: 1.5; max-width: 200px; text-align: center;\"><span class=\"nodeLabel\" style=\"fill: #333; color: #333;\">退回入库</span></section></foreignObject></g></g><g transform=\"translate(1128.9375, 35)\" id=\"flowchart-F-13\" class=\"node default\"><rect height=\"54\" width=\"126\" y=\"-27\" x=\"-63\" ry=\"5\" rx=\"5\" style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\" class=\"basic label-container\"></rect><g transform=\"translate(-48, -12)\" style=\"font-family: \'trebuchet ms\',verdana,arial,sans-serif; color: #333; text-align: center;\" class=\"label\"><rect style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\"></rect><foreignObject height=\"24\" width=\"96\"><section xmlns=\"http://www.w3.org/1999/xhtml\" style=\"display: table-cell; white-space: nowrap; line-height: 1.5; max-width: 200px; text-align: center;\"><span class=\"nodeLabel\" style=\"fill: #333; color: #333;\">退款给消费者</span></section></foreignObject></g></g><g transform=\"translate(1313.875, 87)\" id=\"flowchart-G-15\" class=\"node default\"><rect height=\"54\" width=\"92\" y=\"-27\" x=\"-46\" style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\" class=\"basic label-container\"></rect><g transform=\"translate(-16, -12)\" style=\"font-family: \'trebuchet ms\',verdana,arial,sans-serif; color: #333; text-align: center;\" class=\"label\"><rect style=\"fill: #ECECFF; stroke: #9370DB; stroke-width: 1px;\"></rect><foreignObject height=\"24\" width=\"32\"><section xmlns=\"http://www.w3.org/1999/xhtml\" style=\"display: table-cell; white-space: nowrap; line-height: 1.5; max-width: 200px; text-align: center;\"><span class=\"nodeLabel\" style=\"fill: #333; color: #333;\">完成</span></section></foreignObject></g></g></g></g></g></svg></pre>\r\n    \r\n  \r\n        \r\n      \r\n      \r\n    </section><p style=\"font-size: 0px; line-height: 0; margin: 0px;\">&nbsp;</p>', 1, '1742959419', NULL, 1, 'introduction', 99, 0);
INSERT INTO `sys_help` VALUES (2, '部署说明', '<p style=\"font-size: 0px; line-height: 0; margin: 0px;\">&nbsp;</p><section style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px\"><h1 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 1em; border-bottom: 2px solid #0F4C81; margin: 2em auto 1em; color: #3f3f3f; font-weight: bold;margin-transform: translateY( 0\">启航电商ERP开源版本部署教程</h1><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system)-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">启航电商ERP2.0是一个部署即可使用的开源电商ERP系统，今天给大家讲一讲如何进行部署，下面以Ubuntu系统为例详细介绍部署完整过程，有需要的兄弟们自取。</p><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">环境版本</h2><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• Ubuntu：22+</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• MySQL：8.x</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• Redis：7.x</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• Java：17</li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">一、安装mysql8</h2><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 1、更新安装包管理工具<br>sudo apt-get update</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 2、安装 mysql数据库，过程中的选项选择 y<br>sudo apt-get install mysql-server</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 3、启动mysql命令如下 （停止mysql的命令为：sudo service mysql stop）<br>sudo service mysql start</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 4、查看mysql的启动状态<br>sudo service mysql status</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 5、设置开机自启<br>sudo systemctl enable mysql</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 6、登录（初始密码为空）<br>mysql -u root -p</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 7、设置root账户连接及密码</li></ul><pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">#进入mysql<br>use&nbsp;mysql;<br>&nbsp;<br>#查看需要修改的root用户数据<br>select&nbsp;host,&nbsp;user,&nbsp;authentication_string&nbsp;from&nbsp;user;<br>&nbsp;<br>#为root账号赋权<br>ALTER&nbsp;USER&nbsp;\'root\'@\'localhost\'&nbsp;IDENTIFIED&nbsp;WITH&nbsp;mysql_native_password&nbsp;BY&nbsp;\'Andy_123\';<br>&nbsp;<br>#刷新权限<br>FLUSH&nbsp;PRIVILEGES;<br>&nbsp;<br>#退出mysql控制台<br>exit;</code></pre><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 8、设置远程访问登录<pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">#进入mysql<br>use&nbsp;mysql;<br><br>#设置登录ip为%通配符，取消登录ip限制<br>update&nbsp;user&nbsp;set&nbsp;host&nbsp;=&nbsp;\'%\'&nbsp;where&nbsp;user&nbsp;=&nbsp;\'root\'&nbsp;and&nbsp;host&nbsp;=&nbsp;\'localhost\';<br><br>#刷新权限<br>FLUSH&nbsp;PRIVILEGES;<br><br>#查看数据情况<br>select&nbsp;host,&nbsp;user,&nbsp;authentication_string&nbsp;from&nbsp;user;<br><br>#退出mysql控制台<br>exit;</code></pre><pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">#修改mysql配置文件，取消对远程ip为127.0.0.1的绑定<br>#将bind-address、mysqlx-bind-address这两行注释掉<br>vim&nbsp;/etc/mysql/mysql.conf.d/mysqld.cnf</code></pre></li><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 重启:<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">service mysql restart</code></li></ul><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 修改配置文件允许远程访问mysql</li></ul><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 设置远程访问及密码</li></ul><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 9、防火墙开放3306端口<br><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo ufw allow 3306/tcp</code></li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">二、安装Redis7</h2><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 更新：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo apt update</code></li></ul><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">Redis 7 可能不在默认的 Ubuntu 存储库中，因此你可能需要添加 Redis 官方的 PPA（个人包档案）来安装最新版本。以下是步骤：</p><h5 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px 0.5em; color: #0F4C81; font-weight: bold\">添加 Redis 官方 PPA</h5><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 1、安装 <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">software-properties-common</code>（如果尚未安装）：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo apt install software-properties-common</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 2、添加 Redis PPA：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo add-apt-repository ppa:redislabs/redis</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 3、更新包列表：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo apt update</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 4、安装 Redis 7：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo apt install redis</code></li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">检查 Redis 版本</h4><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">确认安装的 Redis 版本是否为 7：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">redis-server --version</code></p><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">配置 Redis</h4><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">Redis 配置文件通常位于 <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">/etc/redis/redis.conf</code>。你可以根据需要编辑该文件来调整 Redis 的配置：</p><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\"><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo vim /etc/redis/redis.conf</code></p><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">常见的配置项包括：</p><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\"><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">bind</code></strong>：设置 Redis 监听的 IP 地址。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\"><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">port</code></strong>：设置 Redis 监听的端口。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\"><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">requirepass</code></strong>：设置 Redis 的访问密码。</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">启动和管理 Redis 服务</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 1、检查服务文件：</li></ul><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">Redis 的服务文件通常应该位于 <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">/lib/systemd/system/redis-server.service</code>。</p><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">检查该文件是否存在：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">ls /lib/systemd/system/redis-server.service</code></p><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 2、如果文件存在，你可以重新加载系统服务文件并尝试启动服务：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo systemctl daemon-reload</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 3、设置 Redis 服务开机启动：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo systemctl enable redis-server</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 4、启动：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo systemctl start redis-server</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 5、测试：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">redis-cli -h 127.0.0.1 -p 6379</code></li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">三、安装openjdk17</h2><pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">sudo&nbsp;apt&nbsp;update<br>sudo&nbsp;apt&nbsp;upgrade<br>sudo&nbsp;apt&nbsp;install&nbsp;openjdk-17-jdk<br>java&nbsp;--version</code></pre><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">四、安装nginx</h2><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">下载解压</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">wget https://nginx.org/download/nginx-1.22.1.tar.gz</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">tar -zxvf nginx-1.22.1.tar.gz</code></li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">编译安装</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 安装依赖<pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">sudo&nbsp;apt&nbsp;update<br>&nbsp;&nbsp;sudo&nbsp;apt&nbsp;install&nbsp;-y&nbsp;build-essential&nbsp;libpcre3&nbsp;libpcre3-dev&nbsp;libssl-dev&nbsp;zlib1g&nbsp;zlib1g-dev</code></pre></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 配置</li><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">cd nginx-1.22.1</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">./configure</code>(默认安装在/usr/local/nginx)</li></ul><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 编译安装<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">make &amp;&amp; make install</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 启动：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo /usr/local/nginx/sbin/nginx</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 测试访问：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">curl http://localhost</code></li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">五、部署及配置</h2><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\"><strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">拉取最新代码：</strong><code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">git clone https://gitee.com/qiliping/qihangerp.git</code></p><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">1、导入SQL数据库</h3><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 远程连接服务器mysql，推荐使用<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">Navicat</code>等数据库工具</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 创建数据库：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">qihang-oms</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 导入sql脚本：进入<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">qihangerp\\docs\\qihang-oms.sql</code>导入sql</li></ul><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">2、部署后端</h3><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 配置项目Mysql数据库访问密码：<pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">spring:<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;datasource:<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;driverClassName:&nbsp;com.mysql.cj.jdbc.Driver<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;url:&nbsp;jdbc:mysql://localhost:3306/qihang-oms?useUnicode=true&amp;characterEncoding=utf8&amp;zeroDateTimeBehavior=convertToNull&amp;useSSL=true&amp;serverTimezone=GMT%2B8<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;username:&nbsp;root<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;password:&nbsp;Andy_123</code></pre></li><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 进入<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">app</code>项目</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 打开项目配置文件：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">application.yaml</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 修改配置：</li></ul><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 进入项目根目录：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">qihangerp</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 项目打包<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">mvn clean package</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 上传到服务器<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">/opt/qihangerp</code><br>  <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">scp -P 22 -r app-3.0.2.jar root@x.x.x.x:/opt/qihangerp</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 运行：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">nohup java -jar app-3.0.2.jar &gt; output.log 2&gt;&amp;1 &amp;</code></li></ul><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">3、部署前端</h3><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 打包``</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 上传<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">/opt/qihangerp/dist</code>:<br>  <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">scp -P 22 -r dist root@x.x.x.x:/opt/qihangerp/dist</code></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 修改nginx配置：<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">vim /usr/local/nginx/conf/nginx.conf</code><pre class=\"hljs code__pre\" style=\"text-align: left; line-height: 1.5; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; overflow-x: auto; border-radius: 8px; margin: 10px 8px; padding: 0 !important;\"><span class=\"mac-sign\" style=\"display: flex; padding: 10px 14px 0;\" hidden=\"\"><svg xmlns=\"http://www.w3.org/2000/svg\" version=\"1.1\" x=\"0px\" y=\"0px\" width=\"45px\" height=\"13px\" viewBox=\"0 0 450 130\">\r\n    <ellipse cx=\"50\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(220,60,54)\" stroke-width=\"2\" fill=\"rgb(237,108,96)\"></ellipse>\r\n    <ellipse cx=\"225\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(218,151,33)\" stroke-width=\"2\" fill=\"rgb(247,193,81)\"></ellipse>\r\n    <ellipse cx=\"400\" cy=\"65\" rx=\"50\" ry=\"52\" stroke=\"rgb(27,161,37)\" stroke-width=\"2\" fill=\"rgb(100,200,86)\"></ellipse>\r\n  </svg></span><code class=\"language-\" style=\"display: -webkit-box; padding: 0.5em 1em 1em; overflow-x: auto; text-indent: 0; text-align: left; line-height: 1.75; font-family: Menlo, Operator Mono, Consolas, Monaco, monospace; font-size: 14px; margin: 0; white-space: nowrap;\">#&nbsp;前端web配置<br>location&nbsp;/&nbsp;{<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;root&nbsp;&nbsp;&nbsp;/opt/qihangerp/dist;<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;index&nbsp;&nbsp;index.html&nbsp;index.htm;<br>&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;try_files&nbsp;$uri&nbsp;$uri/&nbsp;/index.html;<br>&nbsp;&nbsp;&nbsp;&nbsp;}<br>#&nbsp;增加后台api转发<br>location&nbsp;/prod-api/&nbsp;{<br>&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header&nbsp;Host&nbsp;$http_host;<br>&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header&nbsp;X-Real-IP&nbsp;$remote_addr;<br>&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header&nbsp;REMOTE-HOST&nbsp;$remote_addr;<br>&nbsp;&nbsp;&nbsp;&nbsp;proxy_set_header&nbsp;X-Forwarded-For&nbsp;$proxy_add_x_forwarded_for;<br>&nbsp;&nbsp;&nbsp;&nbsp;proxy_pass&nbsp;http://localhost:8088/;<br>}</code></pre></li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 重启nginx： <code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">sudo /usr/local/nginx/sbin/nginx -s reload</code></li></ul><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\"><strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">至此部署完成，需要注意的是云服务器需要配置安全策略才能远程进行访问</strong></p><hr style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; border-style: solid; border-width: 2px 0 0; border-color: rgba(0,0,0,0.1); -webkit-transform-origin: 0 0; -webkit-transform: scale(1, 0.5); transform-origin: 0 0; transform: scale(1, 0.5); height: 0.4em; margin: 1.5em 0\">\r\n    \r\n  \r\n        \r\n      \r\n      \r\n    </section><p style=\"font-size: 0px; line-height: 0; margin: 0px;\">&nbsp;</p>', 2, NULL, NULL, 1, 'bushushuoming', 99, 0);
INSERT INTO `sys_help` VALUES (3, '系统简介', '<p style=\"font-size: 0px; line-height: 0; margin: 0px;\">&nbsp;</p><section style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px\"><h1 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 1em; border-bottom: 2px solid #0F4C81; margin: 2em auto 1em; color: #3f3f3f; font-weight: bold;margin-transform: translateY( 0\">启航电商ERP2.0版本</h1><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system)-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">一、介绍</h2><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">启航电商OMS系统是一套多平台多店铺订单处理系统，本项目后端采用SpringCloudAlibaba 微服务架构，前端采用Vue2开发。</p><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">平台支持：淘宝、京东、拼多多、抖店、微信视频号。</p><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">主要功能包括：订单管理、打单发货（电子面单打印）、售后处理、商品管理等。</p><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">TODO</h3><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 库存模块（库存查询、入库操作、出库操作）</li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">二、主体功能及流程</h2><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">主体功能</h3><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">1、订单管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单管理：聚合订单查询、详情、管理。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单明细：聚合订单明细查询。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺订单管理：订单API拉取、订单API更新、订单手动推送等，支持淘宝天猫、京东、拼多多、抖店、微信视频号。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单更新日志：查询更新日志，主动排错。</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">2、发货管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 订单打印：电子面单取号、打印、发货，支持淘宝天猫、京东、拼多多、抖店、微信视频号。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 备货清单：电子面单取号之后会加入备货清单，提供给仓库备货查询。发货之后会从备货清单中移除。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 发货记录：发货记录，提供手动发货功能。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 物流跟踪：提供发货物流查询。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 快递公司管理：管理发货的快递公司。</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">3、售后管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后管理：聚合售后查询、详情、管理。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺售后管理：售后API拉取、售后API更新、手动推送、售后操作（同意、备注）。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后处理记录：售后处理的记录查询，提供手动售后处理功能。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 售后更新日志：查询更新日志，主动排错。</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">4、商品管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• ERP商品SKU：管理ERP商品SKU，提供手动录入、API接收功能。</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺商品管理：店铺商品管理，店铺商品API拉取、店铺商品API更新。</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">4、店铺管理</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺列表</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 开放平台设置</li></ul><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\"><strong style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: inherit; color: #0F4C81; font-weight: bold\">支持多店铺管理</strong></p><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 店铺参数设置（appkey等）</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 基础管理</li><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 发货地址库</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 发货物流公司库</li></ul></ul><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">主体流程</h3><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">1、主流程</h4><p style=\" text-align: justify; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 1.5em 8px; letter-spacing: 0.1em; color: #3f3f3f\">店铺参数设置--&gt;ERP商品SKU录入--&gt;<br>店铺商品拉取（程序会根据SKU编码自动关联ERP商品SKU）--&gt;<br>API拉取订单(程序根据平台skuid查找店铺)--&gt;<br>订单打印（消息通知备货）--&gt;<br>备货（备货清单）--&gt;<br>发货出库（消息通知接口处理）--&gt;<br>查询发货(物流跟踪)--&gt;<br>店铺售后拉取--&gt;<br>售后操作（拦截订单、补发商品、换货、退货）--&gt;<br>售后记录查询</p><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">库存并发设计</h3><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 1、入库实时增加库存；</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 2、出库先锁定库存：设计一张表存储<code style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 90%; color: #d14; background: rgba(27,31,35,.05); padding: 3px 5px; border-radius: 4px\">库存锁定</code>，状态：已结算、未结算、已释放，每天闲时进行库存结算；</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• 3、查询库存时，需要把未结算的锁定库存扣减掉；</li></ul><h2 style=\" text-align: center; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 16.8px; display: table; padding: 0 0.2em; margin: 4em auto 2em; color: #fff; background: #0F4C81; font-weight: bold\">三、软件架构</h2><h3 style=\" text-align: left; line-height: 1.2; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 15.400000000000002px; padding-left: 8px; border-left: 3px solid #0F4C81; margin: 2em 8px 0.75em 0; color: #3f3f3f; font-weight: bold\">1、开发环境级组件</h3><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.5em; color: #0F4C81; font-weight: bold\">1.1 开发环境</h4><ul style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; list-style: circle; padding-left: 1em; margin-left: 0; color: #3f3f3f\"><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• Jdk：17</li><li style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; text-indent: -1em; display: block; margin: 0.2em 8px; color: #3f3f3f\">• Nodejs：v16.20.0</li></ul><h4 style=\" text-align: left; line-height: 1.75; font-family: -apple-system-font,BlinkMacSystemFont, Helvetica Neue, PingFang SC, Hiragino Sans GB , Microsoft YaHei UI , Microsoft YaHei ,Arial,sans-serif; font-size: 14px; margin: 2em 8px 0.